+fn parse_policy_mode(value: &str) -> Option<PolicyMode> {
+    match value.trim().to_ascii_lowercase().as_str() {
+        "deny" | "block" => Some(PolicyMode::Deny),
+        "warn" | "warning" => Some(PolicyMode::Warn),
+        "log" | "log-only" | "logonly" => Some(PolicyMode::Log),
+        _ => None,
+    }
